import { Component, OnInit } from '@angular/core';
import { DashboardData } from '@app/shared/models';
import { ApiService } from '@app/core/services';

@Component({
  selector: 'app-dashboard',
  templateUrl: './dashboard.component.html',
  styleUrls: ['./dashboard.component.css']
})
export class DashboardComponent implements OnInit {
  dashboardData: DashboardData = {
    totalStudents: 0,
    totalEnrollments: 0,
    totalPromoters: 0
  };
  loading = false;
  error: string | null = null;

  // Panel visibility
  showStudentsPanel = false;
  showPromotersPanel = false;
  showEnrollmentPanel = false;

  constructor(private apiService: ApiService) {}

  ngOnInit(): void {
    this.loadDashboard();
  }

  loadDashboard(): void {
    this.loading = true;
    this.error = null;
    this.apiService.getDashboard().subscribe({
      next: (data) => {
        this.dashboardData = data;
        this.loading = false;
      },
      error: (err) => {
        this.error = 'Error al cargar el dashboard';
        this.loading = false;
        console.error(err);
      }
    });
  }

  openStudentsPanel(): void {
    this.closeAllPanels();
    this.showStudentsPanel = true;
  }

  openPromotersPanel(): void {
    this.closeAllPanels();
    this.showPromotersPanel = true;
  }

  openEnrollmentPanel(): void {
    this.closeAllPanels();
    this.showEnrollmentPanel = true;
  }

  closeAllPanels(): void {
    this.showStudentsPanel = false;
    this.showPromotersPanel = false;
    this.showEnrollmentPanel = false;
  }
}
<main class="app-shell">
  <header class="topbar">
    <div class="brand">
      <span class="brand-small">Edu</span><span class="brand-large">Futuro</span>
    </div>
    <h1>SISTEMA DE GESTIÓN</h1>
    <p class="subtitle">EduFuturo</p>
  </header>

  <section class="dashboard-card" *ngIf="!loading">
    <div class="dashboard-summary">
      <article class="stat-card">
        <p class="stat-title">Total estudiantes</p>
        <p class="stat-value">{{ dashboardData.totalStudents }}</p>
        <button class="btn" (click)="openStudentsPanel()">Ver Estudiantes</button>
      </article>
      <article class="stat-card highlight">
        <p class="stat-title">Total Matrículas</p>
        <p class="stat-value">{{ dashboardData.totalEnrollments }}</p>
        <button class="btn" (click)="openEnrollmentPanel()">Registrar Matrícula</button>
      </article>
      <article class="stat-card">
        <p class="stat-title">Total Promotores</p>
        <p class="stat-value">{{ dashboardData.totalPromoters }}</p>
        <button class="btn" (click)="openPromotersPanel()">Ver Promotores</button>
      </article>
    </div>
  </section>

  <section class="content-panel" [class.hidden]="!showStudentsPanel">
    <div class="panel-header">
      <h2>Lista de Estudiantes</h2>
      <button class="btn secondary" (click)="closeAllPanels()">Cerrar</button>
    </div>
    <app-students-list *ngIf="showStudentsPanel"></app-students-list>
  </section>

  <section class="content-panel" [class.hidden]="!showPromotersPanel">
    <div class="panel-header">
      <h2>Lista de Promotores</h2>
      <button class="btn secondary" (click)="closeAllPanels()">Cerrar</button>
    </div>
    <app-promoters-list *ngIf="showPromotersPanel"></app-promoters-list>
  </section>

  <section class="content-panel" [class.hidden]="!showEnrollmentPanel">
    <div class="panel-header">
      <h2>Registrar Matrícula</h2>
      <button class="btn secondary" (click)="closeAllPanels()">Cancelar</button>
    </div>
    <app-enrollment-form *ngIf="showEnrollmentPanel"></app-enrollment-form>
  </section>
</main>
